/**
 * ResponsePanel — Shows autonomous response pipeline results:
 * blocklist enforcement, SOC alert dispatch, incident ticket, and verification.
 */

const STATUS_BADGE = {
  idle:     { cls: "bg-gray-800 text-gray-500",              label: "IDLE" },
  running:  { cls: "bg-blue-900 text-blue-300 animate-pulse", label: "RUNNING" },
  complete: { cls: "bg-emerald-900 text-emerald-300",         label: "COMPLETE" },
  skipped:  { cls: "bg-gray-800 text-gray-500",               label: "SKIPPED" },
  error:    { cls: "bg-red-900 text-red-400",                 label: "ERROR" },
};

function StatusBadge({ status }) {
  const cfg = STATUS_BADGE[status] || STATUS_BADGE.idle;
  return (
    <span className={`text-[10px] font-mono font-bold px-2 py-0.5 rounded uppercase tracking-widest ${cfg.cls}`}>
      {cfg.label}
    </span>
  );
}

function SectionHeader({ title }) {
  return (
    <h4 className="text-[11px] font-mono uppercase tracking-widest text-gray-500 mb-2 border-b border-gray-800 pb-1">
      {title}
    </h4>
  );
}

function EmptyState({ message }) {
  return <p className="text-gray-600 text-xs font-mono italic">{message}</p>;
}

function BlocklistCard({ data }) {
  if (!data) return <EmptyState message="Waiting for BlocklistAgent…" />;
  const statusColor = data.status === "success" ? "text-emerald-400" : data.status === "partial" ? "text-yellow-400" : "text-red-400";
  return (
    <div className="space-y-2">
      <div className="flex items-center gap-3 flex-wrap">
        <span className={`text-xs font-mono font-bold uppercase ${statusColor}`}>{data.status}</span>
        <span className="text-gray-500 text-xs font-mono">{data.actions_taken} actions taken</span>
      </div>
      {data.blocked_ips?.length > 0 && (
        <div>
          <p className="text-[11px] text-gray-500 font-mono mb-1">Blocked IPs ({data.blocked_ips.length})</p>
          <div className="flex flex-wrap gap-1">
            {data.blocked_ips.slice(0, 6).map((ip, i) => (
              <span key={i} className="bg-red-950 border border-red-800 text-red-300 text-[10px] font-mono px-1.5 py-0.5 rounded">
                {ip}
              </span>
            ))}
            {data.blocked_ips.length > 6 && (
              <span className="text-gray-600 text-[10px] font-mono px-1.5 py-0.5">+{data.blocked_ips.length - 6} more</span>
            )}
          </div>
        </div>
      )}
      {data.blocked_domains?.length > 0 && (
        <div>
          <p className="text-[11px] text-gray-500 font-mono mb-1">DNS Sinkholed ({data.blocked_domains.length})</p>
          <div className="flex flex-wrap gap-1">
            {data.blocked_domains.slice(0, 4).map((d, i) => (
              <span key={i} className="bg-orange-950 border border-orange-800 text-orange-300 text-[10px] font-mono px-1.5 py-0.5 rounded">
                {d}
              </span>
            ))}
            {data.blocked_domains.length > 4 && (
              <span className="text-gray-600 text-[10px] font-mono px-1.5 py-0.5">+{data.blocked_domains.length - 4} more</span>
            )}
          </div>
        </div>
      )}
      {data.firewall_rule_ids?.length > 0 && (
        <p className="text-[11px] text-gray-600 font-mono">
          Rule IDs: {data.firewall_rule_ids.slice(0, 2).join(", ")}
          {data.firewall_rule_ids.length > 2 ? ` +${data.firewall_rule_ids.length - 2} more` : ""}
        </p>
      )}
      {data.notes && <p className="text-[11px] text-gray-600 font-mono">{data.notes}</p>}
    </div>
  );
}

function AlertCard({ data }) {
  if (!data) return <EmptyState message="Waiting for AlertAgent…" />;
  const sevColor = { critical: "text-red-400", high: "text-orange-400", medium: "text-yellow-400", low: "text-green-400" };
  return (
    <div className="space-y-2">
      <div className="flex items-center gap-2 flex-wrap">
        <span className={`text-xs font-mono font-bold uppercase ${sevColor[data.severity] || "text-gray-400"}`}>
          {data.severity}
        </span>
        <span className={`text-[10px] font-mono ${data.status === "sent" ? "text-emerald-400" : "text-red-400"}`}>
          {data.status === "sent" ? "✓ Dispatched" : "✗ Failed"}
        </span>
        {data.alert_id && (
          <span className="text-gray-600 text-[10px] font-mono">{data.alert_id}</span>
        )}
      </div>
      {data.subject && (
        <p className="text-xs font-mono text-gray-200 font-semibold leading-snug">{data.subject}</p>
      )}
      {data.recipients?.length > 0 && (
        <p className="text-[11px] text-gray-500 font-mono">To: {data.recipients.join(", ")}</p>
      )}
      {data.requires_human_action && data.human_actions?.length > 0 && (
        <div className="bg-yellow-950 border border-yellow-800 rounded p-2">
          <p className="text-[10px] text-yellow-400 font-mono font-bold mb-1">HUMAN ACTION REQUIRED</p>
          {data.human_actions.slice(0, 2).map((a, i) => (
            <p key={i} className="text-[10px] text-yellow-300 font-mono">› {a}</p>
          ))}
        </div>
      )}
      {data.sla_minutes && (
        <p className="text-[11px] text-gray-600 font-mono">SLA: {data.sla_minutes} minutes · {data.escalation_path}</p>
      )}
    </div>
  );
}

function TicketCard({ data }) {
  if (!data) return <EmptyState message="Waiting for TicketAgent…" />;
  const sevColor = { critical: "text-red-400", high: "text-orange-400", medium: "text-yellow-400", low: "text-green-400" };
  return (
    <div className="space-y-2">
      <div className="flex items-center gap-2 flex-wrap">
        <span className="text-emerald-400 text-xs font-mono font-bold">{data.ticket_id}</span>
        <span className={`text-[10px] font-mono uppercase ${sevColor[data.severity?.toLowerCase()] || "text-gray-400"}`}>
          {data.severity}
        </span>
        <span className="bg-blue-900 text-blue-300 text-[10px] font-mono px-1.5 py-0.5 rounded uppercase">
          {data.status}
        </span>
      </div>
      {data.title && (
        <p className="text-xs font-mono text-gray-200 font-semibold leading-snug">{data.title}</p>
      )}
      <div className="flex gap-4">
        {data.sla_hours && (
          <p className="text-[11px] text-gray-500 font-mono">SLA: {data.sla_hours}h</p>
        )}
        {data.assigned_to && (
          <p className="text-[11px] text-gray-500 font-mono">Assigned: {data.assigned_to}</p>
        )}
      </div>
      {data.remediation_checklist?.length > 0 && (
        <div>
          <p className="text-[11px] text-gray-500 font-mono mb-1">Remediation checklist ({data.remediation_checklist.length} items)</p>
          {data.remediation_checklist.slice(0, 3).map((item, i) => (
            <p key={i} className="text-[10px] text-gray-400 font-mono">☐ {item}</p>
          ))}
          {data.remediation_checklist.length > 3 && (
            <p className="text-[10px] text-gray-600 font-mono">…and {data.remediation_checklist.length - 3} more</p>
          )}
        </div>
      )}
    </div>
  );
}

function VerificationCard({ data }) {
  if (!data) return <EmptyState message="Waiting for VerificationAgent…" />;
  const allPassed = data.overall_status === "verified";
  return (
    <div className="space-y-2">
      <div className="flex items-center gap-2">
        <span className={`text-xs font-mono font-bold uppercase ${allPassed ? "text-emerald-400" : "text-yellow-400"}`}>
          {allPassed ? "✓ Verified" : "⚠ " + data.overall_status}
        </span>
        {data.iteration_label && (
          <span className="text-gray-600 text-[10px] font-mono">{data.iteration_label}</span>
        )}
      </div>
      {data.checks_passed?.length > 0 && (
        <div>
          <p className="text-[11px] text-emerald-500 font-mono">{data.checks_passed.length} checks passed</p>
        </div>
      )}
      {data.checks_failed?.length > 0 && (
        <div>
          <p className="text-[11px] text-red-400 font-mono mb-1">{data.checks_failed.length} checks failed:</p>
          {data.checks_failed.map((c, i) => (
            <p key={i} className="text-[10px] text-red-300 font-mono">✗ {c}</p>
          ))}
        </div>
      )}
      {data.escalation_required && (
        <div className="bg-red-950 border border-red-800 rounded p-2">
          <p className="text-[10px] text-red-300 font-mono font-bold">ESCALATED TO HUMAN ANALYST</p>
          <p className="text-[10px] text-red-400 font-mono">{data.notes}</p>
        </div>
      )}
      {!data.escalation_required && data.notes && (
        <p className="text-[11px] text-gray-600 font-mono">{data.notes}</p>
      )}
    </div>
  );
}

export default function ResponsePanel({ response }) {
  if (!response || response.status === "idle") {
    return (
      <div className="bg-gray-950 border border-gray-800 rounded-xl p-5 flex items-center justify-center min-h-[120px]">
        <p className="text-gray-600 text-sm font-mono">
          Response pipeline will trigger automatically for confirmed high/critical threats…
        </p>
      </div>
    );
  }

  if (response.status === "skipped") {
    return (
      <div className="bg-gray-950 border border-gray-800 rounded-xl p-5 flex items-center justify-center min-h-[120px]">
        <p className="text-gray-600 text-sm font-mono">
          No autonomous response triggered — threat below high/critical threshold.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Overall status banner */}
      <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 flex items-center justify-between">
        <div>
          <p className="text-xs font-mono text-gray-400 mb-0.5">Autonomous Response Pipeline</p>
          <p className="text-[11px] font-mono text-gray-600">
            {response.status === "running"
              ? "Executing response actions…"
              : response.status === "complete"
              ? "All response actions executed and verified"
              : response.status === "error"
              ? response.error || "Response pipeline encountered an error"
              : ""}
          </p>
        </div>
        <StatusBadge status={response.status} />
      </div>

      {/* Four response result cards */}
      <div className="grid grid-cols-1 gap-4">
        <div className="bg-gray-950 border border-gray-800 rounded-xl p-4">
          <SectionHeader title="Firewall Blocklist" />
          <BlocklistCard data={response.blocklist} />
        </div>

        <div className="bg-gray-950 border border-gray-800 rounded-xl p-4">
          <SectionHeader title="SOC Alert" />
          <AlertCard data={response.alert} />
        </div>

        <div className="bg-gray-950 border border-gray-800 rounded-xl p-4">
          <SectionHeader title="Incident Ticket" />
          <TicketCard data={response.ticket} />
        </div>

        <div className="bg-gray-950 border border-gray-800 rounded-xl p-4">
          <SectionHeader title="Verification Loop" />
          <VerificationCard data={response.verification} />
        </div>
      </div>
    </div>
  );
}
